async function handleLearn(ctx: Context, args: string[]): Promise<void> {
  const profile = findProfile(args[0]);
  if (!profile) {
    await ctx.reply(profileNotFound(args[0]));
    return;
  }
  const runId = args[1];
  let candidates: IntelLearningCandidate[];
  if (runId) {
    candidates = getService().draftLearningCandidates(profile, runId);
  } else {
    candidates = getService().listLearningCandidates({
      profileId: profile.id,
      status: "candidate",
      limit: 10,
    });
  }
  if (candidates.length === 0) {
    await ctx.reply(`Profile "${profile.id}" 目前沒有可審核的 learning candidates。`);
    return;
  }
  await sendLearningCandidateList(ctx, candidates, runId ?? candidates[0].runId);
}

