  const profile = findProfile(profileId);
  if (!profile) {
    await ctx.reply(profileNotFound(profileId));
    return;
  }
  if (kind !== "daily" || !time || args.length !== 3) {
    await ctx.reply("用法：/intel schedule <profile-id> daily <HH:MM>");
    return;
  }
  try {
    const entry = await addDailyProfileSchedule(ctx, profile, time);
    await ctx.reply(
